const body = $('Webhook — Scoring de Candidatura').first().json.body;
const appId = body.application_id;
const callbackUrl = body.callback_url;
const skills = String(body.candidate_skills || '').slice(0, 2000);
const summary = String(body.candidate_summary || '').slice(0, 1000);
const experience = String(body.candidate_experience || '').slice(0, 2000);
const jobTitle = String(body.job_title || '');
const requirements = String(body.job_requirements || '').slice(0, 3000);

const fields = [
  'similarity_score: número inteiro entre 0 e 100 representando a correspondência candidato-vaga',
  'match_feedback: explicação detalhada da correspondência, pontos fortes do candidato para esta vaga e lacunas identificadas'
];

const prompt = 'Compara o perfil do candidato com os requisitos da vaga. Responde APENAS com um JSON válido contendo exactamente estes campos:\n' +
  fields.join('\n') +
  '\n\nPerfil do candidato:\nSkills: ' + skills +
  '\nResumo: ' + summary +
  '\nExperiência: ' + experience +
  '\n\nVaga: ' + jobTitle +
  '\nRequisitos: ' + requirements;

const requestBody = JSON.stringify({
  model: $env.OLLAMA_MODEL || 'llama3.2',
  stream: false,
  format: 'json',
  prompt: prompt
});

return [{ json: { application_id: appId, callback_url: callbackUrl, requestBody } }];

const ollamaResp = $input.first().json;
const metadata = $('Construir Prompt Score').first().json;

let result = {};
try {
  const raw = ollamaResp.response || ollamaResp.text || '{}';
  result = JSON.parse(raw);
} catch(e) {
  result = {};
}

const similarityScore = Math.min(100, Math.max(0, parseFloat(result.similarity_score) || 0));
const matchFeedback = String(result.match_feedback || 'Análise de correspondência não disponível.').trim();

const requestBody = JSON.stringify({
  similarity_score: similarityScore,
  match_feedback: matchFeedback
});

return [{
  json: {
    application_id: metadata.application_id,
    callback_url: metadata.callback_url,
    requestBody
  }
}];
